## RAG Workflow

### Complete Pipeline

```boxlang
function buildRAGSystem\( docsPath \) {
    // 1. Load documents
    var docs = aiDocuments\( {
        source: "directory",
        path: docsPath,
        recursive: true
    } \)

    // 2. Chunk documents
    var chunks = aiChunk\( docs, {
        size: 1000,
        overlap: 200
    } \)

    // 3. Create vector memory
    var vectorMemory = aiMemory\( {
        type: "boxvector",
        dimensions: 1536
    } \)

    // 4. Index chunks
    chunks.each\( function\( chunk, index \) {
        vectorMemory.add\( {
            id: "chunk_#index#",
            content: chunk.content,
            metadata: chunk.metadata
        } \)
    } \)

    return vectorMemory
}

// Usage
var vectorMemory = buildRAGSystem\( "docs/" \)
```

### Query RAG System

```boxlang
function queryRAG\( question, vectorMemory \) {
    // Search relevant documents
    var results = vectorMemory.search\( question, limit: 5 \)

    // Build context
    var context = results
        .map\( \( r \) => r.content \)
        .toList\( "\\n\\n" \)

    // Generate answer
    var prompt = """
        Answer based on this context:
        #context#

        Question: #question#
    """

    return ai.chat\( prompt \).content
}
```

